SS.N_GAAP_SKEY AND TT.N_MIS_DATE_SKEY= SS.N_MIS_DATE_SKEY AND TT.N_FORECAST_DATE_SKEY= SS.N_FORECAST_DATE_SKEY AND TT.N_BAL_CAP_COMP_GROUP_SKEY= SS.N_BAL_CAP_COMP_GROUP_SKEY) WHEN MATCHED THEN UPDATE SET  TT.N_RISK_WEIGHT=  CASE  WHEN  COND_1351367610737_10=10 THEN EXP_1351367610737_10 WHEN  COND_1351367610737_10=11 THEN EXP_1351367610737_11 WHEN  COND_1351367610737_10=12 THEN EXP_1351367610737_12 WHEN  COND_1351367610737_10=13 THEN EXP_1351367610737_13 WHEN  COND_1351367610737_10=14 THEN EXP_1351367610737_14 WHEN  COND_1351367610737_10=15 THEN EXP_1351367610737_15 WHEN  COND_1351367610737_10=16 THEN EXP_1351367610737_16 WHEN  COND_1351367610737_10=17 THEN EXP_1351367610737_17 WHEN  COND_1351367610737_10=18 THEN EXP_1351367610737_18 WHEN  COND_1351367610737_10=19 THEN EXP_1351367610737_19 WHEN  COND_1351367610737_10=110 THEN EXP_1351367610737_110 WHEN  COND_1351367610737_10=111 THEN EXP_1351367610737_111 ELSE EXP_1351367610737_112 END;

